This actually shapes the next steps:

1. **The MoEBlock distributed test will need a multi-process launcher, full stop.** The handoff doc's "EP=2 × FSDP=2 suite" cannot run as plain `pytest` once it actually exercises `grouped_dense` end-to-end. Either it's currently hitting this bug (and is silently skipped/xfailed) or it needs to be moved alongside `test_multi_process_distributed_grouped_gemm.py`.

2. **The proper long-term TE fix** is per-device static streams in `common/util/multi_stream.cpp`. Roughly:

   ```cpp
   // Replace `static std::vector<cudaStream_t> streams(num_streams);`
   // (~30 lines) with a per-device cache:
   cudaStream_t get_compute_stream(int idx) {
     int device = 0;
     NVTE_CHECK_CUDA(cudaGetDevice(&device));
     static std::mutex mtx;
     static std::unordered_map<int, std::vector<cudaStream_t>> cache;
     std::lock_guard<std::mutex> lk(mtx);
     auto it = cache.find(device);
     if (it == cache.end()) {
       const size_t n = nvte_get_num_compute_streams();
       std::vector<cudaStream_t> v(n);
       for (size_t i = 0; i < n; ++i)
         NVTE_CHECK_CUDA(cudaStreamCreateWithPriority(
             &v[i], cudaStreamNonBlocking, -1));
       it = cache.emplace(device, std::move(v)).first;
     }
     // ... bounds check on idx ...
     return it->second[idx];
   }
